@keyframes moduix-pulse {
  50% {
    opacity: 0.3;
  }
}

@keyframes moduix-fade-in {
  from {
    opacity: 0;
  }
}

@keyframes moduix-fade-out {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

@keyframes moduix-slide-up {
  from {
    transform: translateY(4px);
    opacity: 0;
  }
}

@keyframes moduix-slide-down {
  from {
    transform: translateY(-4px);
    opacity: 0;
  }
}

@keyframes moduix-spin {
  to {
    transform: rotate(360deg);
  }
}

:root {
  --animation-pulse: moduix-pulse 2.5s ease-in-out infinite;
  --animation-fade-in: moduix-fade-in var(--duration-normal) var(--ease-out);
  --animation-fade-out: moduix-fade-out var(--duration-normal) var(--ease-in);
  --animation-slide-up: moduix-slide-up var(--duration-normal) var(--ease-out);
  --animation-slide-down: moduix-slide-down var(--duration-normal) var(--ease-out);
  --animation-spin: moduix-spin 0.75s linear infinite;
}

:root {
  color-scheme: light;
  --background: oklch(0.982 0.003 285);
  --foreground: oklch(0.175 0.01 285);
  --card: oklch(0.995 0.002 285);
  --card-foreground: oklch(0.175 0.01 285);
  --popover: oklch(0.995 0.002 285);
  --popover-foreground: oklch(0.175 0.01 285);
  --primary: oklch(0.235 0.016 285);
  --primary-foreground: oklch(0.982 0.003 285);
  --secondary: oklch(0.96 0.006 285);
  --secondary-foreground: oklch(0.235 0.016 285);
  --muted: oklch(0.955 0.006 285);
  --muted-foreground: oklch(0.485 0.015 285);
  --accent: oklch(0.95 0.01 285);
  --accent-foreground: oklch(0.235 0.016 285);
  --destructive: oklch(0.565 0.235 22);
  --success: oklch(0.627 0.194 149.214);
  --warning: oklch(0.795 0.184 86.047);
  --border: oklch(0.905 0.008 285);
  --input: oklch(0.905 0.008 285);
  --ring: oklch(0.62 0.035 285);
  --overlay: oklch(0.175 0.014 285 / 0.2);
  --overlay-foreground: oklch(0.175 0.014 285 / 0.07);
  --chart-1: oklch(0.65 0.18 295);
  --chart-2: oklch(0.7 0.14 175);
  --chart-3: oklch(0.72 0.16 55);
  --chart-4: oklch(0.6 0.2 350);
  --chart-5: oklch(0.68 0.13 130);
  --sidebar: oklch(0.975 0.005 285);
  --sidebar-foreground: oklch(0.175 0.01 285);
  --sidebar-primary: oklch(0.235 0.016 285);
  --sidebar-primary-foreground: oklch(0.982 0.003 285);
  --sidebar-accent: oklch(0.95 0.01 285);
  --sidebar-accent-foreground: oklch(0.235 0.016 285);
  --sidebar-border: oklch(0.905 0.008 285);
  --sidebar-ring: oklch(0.62 0.035 285);

  .dark,
  &.dark {
    color-scheme: dark;
    --background: oklch(0.155 0.008 285);
    --foreground: oklch(0.968 0.003 285);
    --card: oklch(0.2 0.011 285);
    --card-foreground: oklch(0.968 0.003 285);
    --popover: oklch(0.2 0.011 285);
    --popover-foreground: oklch(0.968 0.003 285);
    --primary: oklch(0.918 0.007 285);
    --primary-foreground: oklch(0.2 0.011 285);
    --secondary: oklch(0.255 0.012 285);
    --secondary-foreground: oklch(0.968 0.003 285);
    --muted: oklch(0.255 0.012 285);
    --muted-foreground: oklch(0.705 0.016 285);
    --accent: oklch(0.29 0.015 285);
    --accent-foreground: oklch(0.968 0.003 285);
    --destructive: oklch(0.69 0.185 18);
    --success: oklch(0.627 0.194 149.214);
    --warning: oklch(0.795 0.184 86.047);
    --border: oklch(1 0.004 285 / 13%);
    --input: oklch(1 0.004 285 / 17%);
    --ring: oklch(0.585 0.038 285);
    --overlay: oklch(0.105 0.012 285 / 0.74);
    --overlay-foreground: oklch(0.968 0.003 285 / 0.09);
    --chart-1: oklch(0.72 0.17 295);
    --chart-2: oklch(0.76 0.13 175);
    --chart-3: oklch(0.78 0.15 55);
    --chart-4: oklch(0.67 0.19 350);
    --chart-5: oklch(0.74 0.12 130);
    --sidebar: oklch(0.2 0.011 285);
    --sidebar-foreground: oklch(0.968 0.003 285);
    --sidebar-primary: oklch(0.72 0.17 295);
    --sidebar-primary-foreground: oklch(0.155 0.008 285);
    --sidebar-accent: oklch(0.29 0.015 285);
    --sidebar-accent-foreground: oklch(0.968 0.003 285);
    --sidebar-border: oklch(1 0.004 285 / 13%);
    --sidebar-ring: oklch(0.585 0.038 285);
  }

  /* Semantic */
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-success: var(--success);
  --color-warning: var(--warning);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-overlay: var(--overlay);
  --color-overlay-foreground: var(--overlay-foreground);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
}

@layer ui.reset {
  /*
    1. Prevent padding and border from affecting element width. (https://github.com/mozdevs/cssremedy/issues/4)
    2. Remove default margins and padding
    3. Reset all borders.
  */
  *,
  ::after,
  ::before,
  ::backdrop,
  ::file-selector-button {
    box-sizing: border-box; /* 1 */
    margin: 0; /* 2 */
    padding: 0; /* 2 */
    border: 0 solid; /* 3 */
  }

  /*
    1. Use a consistent sensible line-height in all browsers.
    2. Prevent adjustments of font size after orientation changes in iOS.
    3. Use a more readable tab size.
    4. Use the user's configured `sans` font-family by default.
    5. Use the user's configured `sans` font-feature-settings by default.
    6. Use the user's configured `sans` font-variation-settings by default.
    7. Disable tap highlights on iOS.
  */
  html,
  :host {
    line-height: 1.5; /* 1 */
    -webkit-text-size-adjust: 100%; /* 2 */
    tab-size: 4; /* 3 */
    font-family:
      ui-sans-serif, system-ui, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji',
      'Segoe UI Symbol', 'Noto Color Emoji'; /* 4 */
    font-feature-settings: normal; /* 5 */
    font-variation-settings: normal; /* 6 */
    -webkit-tap-highlight-color: transparent; /* 7 */
  }

  /*
    1. Add the correct height in Firefox.
    2. Correct the inheritance of border color in Firefox. (https://bugzilla.mozilla.org/show_bug.cgi?id=190655)
    3. Reset the default border style to a 1px solid border.
  */
  hr {
    height: 0; /* 1 */
    color: inherit; /* 2 */
    border-top-width: 1px; /* 3 */
  }

  /*
    Add the correct text decoration in Chrome, Edge, and Safari.
  */
  abbr:where([title]) {
    -webkit-text-decoration: underline dotted;
    text-decoration: underline dotted;
  }

  /*
    Remove the default font size and weight for headings.
  */
  h1,
  h2,
  h3,
  h4,
  h5,
  h6 {
    font-size: inherit;
    font-weight: inherit;
  }

  /*
    Reset links to optimize for opt-in styling instead of opt-out.
  */
  a {
    color: inherit;
    -webkit-text-decoration: inherit;
    text-decoration: inherit;
  }

  /*
    Add the correct font weight in Edge and Safari.
  */
  b,
  strong {
    font-weight: bolder;
  }

  /*
    1. Use the user's configured `mono` font-family by default.
    2. Use the user's configured `mono` font-feature-settings by default.
    3. Use the user's configured `mono` font-variation-settings by default.
    4. Correct the odd `em` font sizing in all browsers.
  */
  code,
  kbd,
  samp,
  pre {
    font-family:
      ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New',
      monospace; /* 1 */
    font-feature-settings: normal; /* 2 */
    font-variation-settings: normal; /* 3 */
    font-size: 1em; /* 4 */
  }

  /*
    Add the correct font size in all browsers.
  */
  small {
    font-size: 80%;
  }

  /*
    Prevent `sub` and `sup` elements from affecting the line height in all browsers.
  */
  sub,
  sup {
    font-size: 75%;
    line-height: 0;
    position: relative;
    vertical-align: baseline;
  }

  sub {
    bottom: -0.25em;
  }

  sup {
    top: -0.5em;
  }

  /*
    1. Remove text indentation from table contents in Chrome and Safari. (https://bugs.chromium.org/p/chromium/issues/detail?id=999088, https://bugs.webkit.org/show_bug.cgi?id=201297)
    2. Correct table border color inheritance in all Chrome and Safari. (https://bugs.chromium.org/p/chromium/issues/detail?id=935729, https://bugs.webkit.org/show_bug.cgi?id=195016)
    3. Remove gaps between table borders by default.
  */
  table {
    text-indent: 0; /* 1 */
    border-color: inherit; /* 2 */
    border-collapse: collapse; /* 3 */
  }

  /*
    Use the modern Firefox focus style for all focusable elements.
  */
  :-moz-focusring {
    outline: auto;
  }

  /*
    Add the correct vertical alignment in Chrome and Firefox.
  */
  progress {
    vertical-align: baseline;
  }

  /*
    Add the correct display in Chrome and Safari.
  */
  summary {
    display: list-item;
  }

  /*
    Make lists unstyled by default.
  */
  ol,
  ul,
  menu {
    list-style: none;
  }

  /*
    1. Make replaced elements `display: block` by default. (https://github.com/mozdevs/cssremedy/issues/14)
    2. Add `vertical-align: middle` to align replaced elements more sensibly by default. (https://github.com/jensimmons/cssremedy/issues/14#issuecomment-634934210)
        This can trigger a poorly considered lint error in some tools but is included by design.
  */
  img,
  svg,
  video,
  canvas,
  audio,
  iframe,
  embed,
  object {
    display: block; /* 1 */
    vertical-align: middle; /* 2 */
  }

  /*
    Constrain images and videos to the parent width and preserve their intrinsic aspect ratio. (https://github.com/mozdevs/cssremedy/issues/14)
  */
  img,
  video {
    max-width: 100%;
    height: auto;
  }

  /*
    1. Inherit font styles in all browsers.
    2. Remove border radius in all browsers.
    3. Remove background color in all browsers.
    4. Ensure consistent opacity for disabled states in all browsers.
  */
  button,
  input,
  select,
  optgroup,
  textarea,
  ::file-selector-button {
    font: inherit; /* 1 */
    font-feature-settings: inherit; /* 1 */
    font-variation-settings: inherit; /* 1 */
    letter-spacing: inherit; /* 1 */
    color: inherit; /* 1 */
    border-radius: 0; /* 2 */
    background-color: transparent; /* 3 */
    opacity: 1; /* 4 */
  }

  /*
    Restore default font weight.
  */
  :where(select:is([multiple], [size])) optgroup {
    font-weight: bolder;
  }

  /*
    Restore indentation.
  */
  :where(select:is([multiple], [size])) optgroup option {
    padding-inline-start: 20px;
  }

  /*
    Restore space after button.
  */
  ::file-selector-button {
    margin-inline-end: 4px;
  }

  /*
    Reset the default placeholder opacity in Firefox. (https://github.com/tailwindlabs/tailwindcss/issues/3300)
  */
  ::placeholder {
    opacity: 1;
  }

  /*
    Set the default placeholder color to a semi-transparent version of the current text color in browsers that do not
    crash when using `color-mix(…)` with `currentcolor`. (https://github.com/tailwindlabs/tailwindcss/issues/17194)
  */
  @supports (contain-intrinsic-size: 1px) /* Safari 17+ */ {
    ::placeholder {
      color: color-mix(in oklab, currentcolor 50%, transparent);
    }
  }

  /*
    Prevent resizing textareas horizontally by default.
  */
  textarea {
    resize: vertical;
  }

  /*
    Remove the inner padding in Chrome and Safari on macOS.
  */
  ::-webkit-search-decoration {
    -webkit-appearance: none;
  }

  /*
    1. Ensure date/time inputs have the same height when empty in iOS Safari.
    2. Ensure text alignment can be changed on date/time inputs in iOS Safari.
  */
  ::-webkit-date-and-time-value {
    min-height: 1lh; /* 1 */
    text-align: inherit; /* 2 */
  }

  /*
    Remove excess padding from pseudo-elements in date/time inputs to ensure consistent height across browsers.
  */
  ::-webkit-datetime-edit-fields-wrapper {
    padding: 0;
  }

  ::-webkit-datetime-edit-year-field,
  ::-webkit-datetime-edit-month-field,
  ::-webkit-datetime-edit-day-field,
  ::-webkit-datetime-edit-hour-field {
    padding-block: 0;
  }

  /*
    Center dropdown marker shown on inputs with paired `<datalist>`s in Chrome. (https://github.com/tailwindlabs/tailwindcss/issues/18499)
  */
  ::-webkit-calendar-picker-indicator {
    line-height: 1;
  }

  /*
    Remove the additional `:invalid` styles in Firefox. (https://github.com/mozilla/gecko-dev/blob/2f9eacd9d3d995c937b4251a5557d95d494c9be1/layout/style/res/forms.css#L728-L737)
  */
  :-moz-ui-invalid {
    box-shadow: none;
  }

  /*
    Correct the inability to style the border radius in iOS Safari.
  */
  button,
  input:where([type='button'], [type='reset'], [type='submit']),
  ::file-selector-button {
    appearance: button;
  }

  /*
    Correct the cursor style of increment and decrement buttons in Safari.
  */
  ::-webkit-inner-spin-button,
  ::-webkit-outer-spin-button {
    height: auto;
  }

  /*
    Make elements with the HTML hidden attribute stay hidden by default.
  */
  [hidden]:where(:not([hidden='until-found'])) {
    display: none !important;
  }
}

/*
 * Control sizes (Input, Button, Select, etc.)
 * Keeps elements in the same row at a consistent height.
 */
:root {
  --size-xs: 24px;
  --size-sm: 32px;
  --size-md: 36px;
  --size-lg: 40px;
  --size-xl: 48px;
}

:root {
  /* Primitives */
  --spacing-0: 0px;
  --spacing-1: 4px;
  --spacing-2: 8px;
  --spacing-3: 12px;
  --spacing-4: 16px;
  --spacing-5: 20px;
  --spacing-6: 24px;
  --spacing-8: 32px;
  --spacing-10: 40px;

  /* Semantic (for components; use primitives directly for larger values) */
  --spacing-xs: var(--spacing-1); /*  4px */
  --spacing-sm: var(--spacing-2); /*  8px */
  --spacing-md: var(--spacing-3); /* 12px */
  --spacing-lg: var(--spacing-4); /* 16px */
  --spacing-xl: var(--spacing-5); /* 20px */
  --spacing-2xl: var(--spacing-6); /* 24px */
}

@layer ui.reset, ui.tokens, ui.base, ui.components;

@import './animations.css' layer(ui.tokens);
@import './borders.css' layer(ui.tokens);
@import './colors.css' layer(ui.tokens);
@import './opacity.css' layer(ui.tokens);
@import './radius.css' layer(ui.tokens);
@import './shadows.css' layer(ui.tokens);
@import './sizing.css' layer(ui.tokens);
@import './spacing.css' layer(ui.tokens);
@import './transforms.css' layer(ui.tokens);
@import './transitions.css' layer(ui.tokens);
@import './typography.css' layer(ui.tokens);
@import './z-index.css' layer(ui.tokens);

:root {
  --scale-popup: 0.9; /* overlays: dialog, popover, tooltip, menu, hover-card, toast, nav-menu */
  --scale-dropdown: 0.95; /* dropdown lists: select, combobox */
}

:root {
  /* Duration */
  --duration-fast: 150ms;
  --duration-normal: 200ms;
  --duration-slow: 350ms;
  --duration-slower: 450ms;

  /* Easing */
  --ease-in: cubic-bezier(0.4, 0, 1, 1);
  --ease-out: cubic-bezier(0, 0, 0.2, 1);
  --ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-standard: ease;
  --ease-spring: cubic-bezier(0.32, 0.72, 0, 1);
  --ease-emphasized: cubic-bezier(0.22, 1, 0.36, 1);

  /* Composed (shorthand) */
  --transition-default: var(--duration-normal) var(--ease-in-out);
  --transition-fast: var(--duration-fast) var(--ease-in-out);
  --transition-slow: var(--duration-slow) var(--ease-in-out);
  --transition-slower: var(--duration-slower) var(--ease-in-out);
  --transition-spring: var(--duration-slower) var(--ease-spring);
  --transition-emphasized: var(--duration-slower) var(--ease-emphasized);
}

:root {
  /* Font-family */
  --font-sans:
    'Noto Sans', ui-sans-serif, system-ui, sans-serif, 'Apple Color Emoji', 'Segoe UI Emoji',
    'Segoe UI Symbol', 'Noto Color Emoji';
  --font-mono:
    ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New',
    monospace;

  /* Weight */
  --weight-regular: 400;
  --weight-medium: 500;
  --weight-semibold: 600;
  --weight-bold: 700;

  /* Font-size */
  --text-xs: 11px;
  --text-sm: 14px;
  --text-md: 16px;
  --text-lg: 18px;
  --text-xl: 20px;
  --text-2xl: 24px;
  --text-3xl: 30px;

  /* Line-height */
  --line-height-text-xs: 14px;
  --line-height-text-sm: 22px;
  --line-height-text-md: 24px;
  --line-height-text-lg: 28px;
  --line-height-text-xl: 32px;
  --line-height-text-2xl: 32px;
  --line-height-text-3xl: 36px;

  /* Letter-spacing */
  --tracking-text-sm: -0.01em; /* -1% */
  --tracking-text-xs: -0.016em; /* -1.6% */
}
